import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function OwnerDashboard() {
  const [stats, setStats] = useState({ totalLots: 0, approvedLots: 0, pendingLots: 0 });
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchOwnerData = async () => {
      try {
        if (localStorage.getItem("role") !== "owner") {
            navigate("/dashboard");
            return;
        }

        const res = await axios.get("/owner/stats");
        setStats(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Failed to load owner data:", err);
      }
    };
    fetchOwnerData();
  }, [navigate]);

  if (loading) return <div style={{ textAlign: "center", padding: "40px" }}><i className="fa-solid fa-spinner fa-spin fa-2x" style={{ color: "var(--accent-primary)" }}></i></div>;

  return (
    <div style={{ animation: "fadeIn 0.5s ease-out" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "32px" }}>
        <div>
          <h1 style={{ fontSize: "2rem", color: "var(--text-primary)", marginBottom: "4px" }}>Owner Portal</h1>
          <p style={{ color: "var(--text-secondary)", margin: 0 }}>Manage your parking properties and reservations.</p>
        </div>
        <button className="btn-primary" onClick={() => {/* To be implemented */}} style={{ width: "auto" }}>
            <i className="fa-solid fa-plus"></i> Add New Parking
        </button>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: "24px", marginBottom: "40px" }}>
        <StatCard title="Total Properties" value={stats.totalLots} icon="fa-building" color="var(--accent-primary)" />
        <StatCard title="Approved Lots" value={stats.approvedLots} icon="fa-circle-check" color="var(--status-success)" />
        <StatCard title="Pending Approval" value={stats.pendingLots} icon="fa-clock" color="var(--status-warning)" />
      </div>

      <div className="card" style={{ padding: "32px", textAlign: "center", background: "var(--bg-secondary)" }}>
        <i className="fa-solid fa-chart-line fa-3x" style={{ color: "var(--text-muted)", marginBottom: "16px" }}></i>
        <h3>Detailed Metrics Coming Soon</h3>
        <p style={{ color: "var(--text-secondary)", maxWidth: "500px", margin: "0 auto" }}>Detailed revenue tracking, active scans, and daily reports are being built for the Owner view.</p>
      </div>
    </div>
  );
}

const StatCard = ({ title, value, icon, color }) => (
  <div style={{ background: "var(--bg-secondary)", padding: "24px", borderRadius: "var(--radius-lg)", boxShadow: "var(--shadow-md)", border: "1px solid var(--border-subtle)", position: "relative", overflow: "hidden", transition: "transform 0.2s ease", cursor: "default" }} onMouseOver={e => e.currentTarget.style.transform = "translateY(-5px)"} onMouseOut={e => e.currentTarget.style.transform = "translateY(0)"}>
    <div style={{ position: "absolute", right: "-10px", top: "-10px", opacity: 0.05, fontSize: "6rem", color: color }}>
        <i className={`fa-solid ${icon}`}></i>
    </div>
    <div style={{ color: "var(--text-secondary)", fontSize: "0.95rem", fontWeight: "600", textTransform: "uppercase", letterSpacing: "0.5px", marginBottom: "8px", display: "flex", alignItems: "center", gap: "8px" }}>
        <i className={`fa-solid ${icon}`} style={{ color: color }}></i> {title}
    </div>
    <div style={{ fontSize: "2.5rem", fontWeight: "800", color: "var(--text-primary)", letterSpacing: "-1px" }}>{value}</div>
  </div>
);
